#include <stdio.h>
#include <ctype.h>
#include <string.h>

int main() {
    char a[1000];
    fgets(a, sizeof(a), stdin);

    // Remove spaces
    int j = 0;
    for (int i = 0; a[i]; i++) {
        if (!isspace(a[i])) {
            a[j++] = a[i];
        }
    }
    a[j] = '\0';

    // Convert to lowercase
    for (int i = 0; a[i]; i++) {
        a[i] = tolower(a[i]);
    }

    int len = strlen(a);
    if (len >= 2) {
        char last_char = a[len - 2];
        if (strchr("aeiouy", last_char)) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    } else {
        printf("NO\n");
    }

    return 0;
}
